import{_ as e,o as i,c as a,a2 as o}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Plugin Affiliate Settings","description":"DinOdds Plugin Affiliate Settings","frontmatter":{"title":"Plugin Affiliate Settings","description":"DinOdds Plugin Affiliate Settings","weight":60,"extra":{"order":60},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/dinodds/affiliate-settings"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/dinodds/affiliate-settings"}],["meta",{"property":"og:title","content":"Plugin Affiliate Settings"}],["meta",{"property":"og:description","content":"DinOdds Plugin Affiliate Settings"}],["meta",{"name":"twitter:title","content":"Plugin Affiliate Settings"}],["meta",{"name":"twitter:description","content":"DinOdds Plugin Affiliate Settings"}]]},"headers":[],"relativePath":"docs/dinodds/affiliate-settings.md","filePath":"docs/dinodds/affiliate-settings.md"}'),s={name:"docs/dinodds/affiliate-settings.md"};function n(l,t,r,d,f,g){return i(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="plugin-affiliate-settings" tabindex="-1">Plugin Affiliate Settings <a class="header-anchor" href="#plugin-affiliate-settings" aria-label="Permalink to &quot;Plugin Affiliate Settings&quot;">​</a></h1><p>To fully integrate with your website, DinOdds gives you the options to set your affiliate settings.</p><h3 id="set-affiliate-links" tabindex="-1">Set Affiliate Links <a class="header-anchor" href="#set-affiliate-links" aria-label="Permalink to &quot;Set Affiliate Links&quot;">​</a></h3><p>For each sportsbook you have an input field to fill in your affiliate link so that they appear in the table at the top or inline with odds values.</p><p><img src="https://media.dinomatic.com/images/docs/dinodds/affiliate-settings.jpg" alt="DinOdds Affiliate Settings"></p><h3 id="change-sportsbook-logos" tabindex="-1">Change Sportsbook Logos <a class="header-anchor" href="#change-sportsbook-logos" aria-label="Permalink to &quot;Change Sportsbook Logos&quot;">​</a></h3><p>You can also change the sportsbook logos instead of using the ones that come by default with the plugin. You can do so by just changing the <strong>Logo URL</strong> field value with the image URL you want to display.</p><h3 id="set-affiliate-link-attributes" tabindex="-1">Set Affiliate Link Attributes <a class="header-anchor" href="#set-affiliate-link-attributes" aria-label="Permalink to &quot;Set Affiliate Link Attributes&quot;">​</a></h3><p>At the bottom of <strong>Sportsbook</strong> section you can set affiliate link attributes such as <code>rel</code> or <code>target</code>. By default they have the most used values but you can choose to set them to whatever you find appropriate for your website.</p>',9)])])}const u=e(s,[["render",n]]);export{h as __pageData,u as default};
